<?php
declare(strict_types=1);require_once __DIR__.'/../app/email_marketing.php';proteger_admin();$pdo=getPDO();email_marketing_ensure_schema($pdo);$templates=$pdo->query("SELECT t.*,v.version_number,(SELECT COUNT(*) FROM email_messages m WHERE m.template_version_id=t.current_version_id) sends,(SELECT COUNT(*) FROM email_messages m WHERE m.template_version_id=t.current_version_id AND m.delivered_at IS NOT NULL) delivered,(SELECT COUNT(*) FROM email_messages m WHERE m.template_version_id=t.current_version_id AND m.first_clicked_at IS NOT NULL) clicks FROM email_templates t LEFT JOIN email_template_versions v ON v.id=t.current_version_id ORDER BY t.updated_at DESC")->fetchAll(PDO::FETCH_ASSOC)?:[];$menu='email_marketing';$page_title='Modelos de e-mail';include __DIR__.'/_header.php';echo email_admin_styles();?><div class="em"><div class="em-head"><div><h1>Modelos de e-mail</h1><p class="text-muted">Conteúdos reutilizáveis e versionados.</p></div><a class="btn btn-primary" href="email_editor.php">+ Criar modelo</a></div><?=email_admin_nav('templates')?><section class="em-card"><div class="em-table"><table><thead><tr><th>Modelo</th><th>Assunto</th><th>Versão</th><th>Envios</th><th>Entregues</th><th>Cliques</th><th></th></tr></thead><tbody><?php foreach($templates as $t):?><tr><td><strong><?=email_h($t['name'])?></strong><div class="text-muted"><?=email_h(date('d/m/Y H:i',strtotime($t['updated_at'])))?></div></td><td><?=email_h($t['subject'])?></td><td>v<?=(int)$t['version_number']?></td><td><?=(int)$t['sends']?></td><td><?=(int)$t['delivered']?></td><td><?=(int)$t['clicks']?></td><td><a class="btn btn-ghost btn-xs" href="email_editor.php?id=<?=(int)$t['id']?>">Editar</a></td></tr><?php endforeach?><?php if(!$templates):?><tr><td colspan="7" class="text-muted">Nenhum modelo criado.</td></tr><?php endif?></tbody></table></div></section></div><?php include __DIR__.'/_footer.php';
